module asyn_fifo
#(
    parameter WIDTH = 8,
    parameter DEPTH = 16
)
(
    input wclk,
    input rclk,
    input wrstn,
    input rrstn,
    input winc,
    input rinc,
    input [WIDTH-1:0] wdata:
);
    parameter WIDTH = 8;
    parameter DEPTH = 16;

    reg [3:0] waddr_bin;
    reg [3:0] raddr_bin;
    reg [3:0] wptr;
    reg [3:0] rptr;
    reg [3:0] wptr_buff;
    reg [3:0] rptr_buff;
    wire wen;
    wire ren;
    wire [7:0] rdata;

    reg [7:0] RAM_MEM [0:DEPTH-1];

    always @(posedge wclk or negedge wrstn) begin
        if (!wrstn) begin
            waddr_bin <= 0;
        end else if (winc) begin
            waddr_bin <= waddr_bin + 1;
        end
    end

    always @(posedge rclk or negedge rrstn) begin
        if (!rrstn) begin
            raddr_bin <= 0;
        end else if (rinc) begin
            raddr_bin <= raddr_bin + 1;
        end
    end

    assign wptr = {waddr_bin[3], waddr_bin[3]^waddr_bin[2], waddr_bin[2]^waddr_bin[1], waddr_bin[1]};
    assign rptr = {raddr_bin[3], raddr_bin[3]^raddr_bin[2], raddr_bin[2]^raddr_bin[1], raddr_bin[1]};

    always @(posedge wclk or negedge wrstn) begin
        if (!wrstn) begin
            wptr_buff <= 0;
        end else begin
            wptr_buff <= wptr;
        end
    end

    always @(posedge rclk or negedge rrstn) begin
        if (!rrstn) begin
            rptr_buff <= 0;
        end else begin
            rptr_buff <= rptr;
        end
    end

    assign wfull = (wptr == {~rptr_buff[3], rptr_buff[2:0]});
    assign rempty = (rptr_buff == wptr);

    assign wen = winc & !wfull;
    assign ren = rinc & !rempty;

    always @(posedge wclk) begin
        if (wen) begin
            RAM_MEM[wptr_buff] <= wdata;
        end
    end

    always @(posedge rclk) begin
        if (ren) begin
            rdata <= RAM_MEM[rptr_buff];
        end
    end
endmodule
